class UserManager:
    def __init__(self):
        self.db = Database()
        self.email_service = EmailService()

    def create_user(self, name, email):
        user = self.db.insert('users', {'name': name, 'email': email})
        return user

    def validate_email(self, email):
        return '@' in email

    def send_welcome_email(self, user):
        subject = f"Welcome {user['name']}"
        self.email_service.send(user['email'], subject, 'Welcome!')

    def delete_user(self, user_id):
        return self.db.delete('users', user_id)

    def get_user_by_email(self, email):
        return self.db.query('users', {'email': email})[0]

    def update_user_profile(self, user_id, profile_data):
        return self.db.update('users', user_id, profile_data)

    def send_notification(self, user_id, message):
        user = self.db.query('users', user_id)[0]
        self.email_service.send(user['email'], 'Notification', message)

def validate_email(email):
    if not email:
        return False
    if '@' not in email:
        return False
    if '.' not in email:
        return False
    return True

def validate_phone(phone):
    if not phone:
        return False
    if len(phone) < 10:
        return False
    if not phone.isdigit():
        return False
    return True

def validate_username(username):
    if not username:
        return False
    if len(username) < 3:
        return False
    if not username.isalnum():
        return False
    return True

function calculatePrice(basePrice, quantity, taxRate, discount) {
  const subtotal = basePrice * quantity;
  const tax = subtotal * taxRate;
  const finalDiscount = subtotal * discount;
  return subtotal + tax - finalDiscount;
}

function applyDiscount(items, code) {
  for (const item of items) {
    if (code === 'SUMMER20') {
      item.price = item.price * 0.8;
    } else if (code === 'FALL15') {
      item.price = item.price * 0.85;
    }
  }
  return items;
}
